import React, { useState } from 'react';

const App = () => {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [categories, setCategories] = useState([]);

  const handlePublish = () => {
    console.log('Publish button clicked!');
  };

  const handleCategoryChange = (event) => {
    setCategories(event.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white max-w-md p-4 shadow-md rounded">
        <label className="text-lg font-bold mb-2">Title:</label>
        <input
          type="text"
          value={title}
          onChange={(event) => setTitle(event.target.value)}
          className="w-full p-2 bg-gray-100 rounded"
        />
        <label className="text-lg font-bold mb-2 mt-4">Content:</label>
        <textarea
          value={content}
          onChange={(event) => setContent(event.target.value)}
          className="w-full p-2 bg-gray-100 rounded"
        />
        <button
          className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
          onClick={handlePublish}
        >
          Publish
        </button>
        <select
          value={categories}
          onChange={handleCategoryChange}
          className="w-full p-2 bg-gray-100 rounded"
        >
          <option value="">Select one</option>
          <option value="Category 1">Category 1</option>
          <option value="Category 2">Category 2</option>
        </select>
      </div>
    </div>
  );
};

export default App;
